def format_retrieved_docs(chunks: list[dict]) -> str:
    """
    Format retrieval results into a clean context block.

    Each chunk: {text, source, title, score, date}
    """
    if not chunks:
        return "No relevant documents found."

    formatted = []
    for i, chunk in enumerate(chunks, 1):
        formatted.append(
            f"""<document index="{i}">
<title>{chunk['title']}</title>
<source>{chunk['source']}</source>
<date>{chunk.get('date', 'Unknown')}</date>
<relevance>{chunk.get('score', 'N/A'):.2f}</relevance>
<content>
{chunk['text'].strip()}
</content>
</document>"""
        )

    return "\n\n".join(formatted)

