def encode_image(image_path: str) -> str:
    """Encode a local image to base64."""
    return base64.b64encode(Path(image_path).read_bytes()).decode("utf-8")

def analyze_ui_screenshot(screenshot_path: str, user_question: str) -> str:
    """Analyze a UI screenshot with a specific question."""
    b64_image = encode_image(screenshot_path)

    response = client.chat.completions.create(
        model="gpt-4o",
        messages=[
            {
                "role": "system",
                "content": "You are a UX analyst. Analyze UI screenshots for "
                           "accessibility, usability, and design issues."
            },
            {
                "role": "user",
                "content": [
                    # Image FIRST, question AFTER — improves comprehension
                    {
                        "type": "image_url",
                        "image_url": {
                            "url": f"data:image/png;base64,{b64_image}",
                            "detail": "high"  # Use 'low' for thumbnails, icons
                        }
                    },
                    {
                        "type": "text",
                        "text": user_question
                    }
                ]
            }
        ],
        max_tokens=1000
    )

    return response.choices[0].message.content

