import numpy as np
from openai import OpenAI

client = OpenAI()

# Define intent prototypes — one per context source
INTENT_PROTOTYPES = {
    "billing": "invoice payment charge refund billing subscription cost pricing",
    "technical": "error bug crash not working broken API integration code",
    "account": "login password access permissions user team admin settings",
    "general": "question help information how does this work"
}

def embed(text: str) -> list[float]:
    return client.embeddings.create(
        model="text-embedding-3-small", input=text
    ).data[0].embedding

# Pre-compute prototype embeddings at startup
prototype_embeddings = {
    intent: embed(text) for intent, text in INTENT_PROTOTYPES.items()
}

def cosine_similarity(a, b) -> float:
    a, b = np.array(a), np.array(b)
    return float(np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b)))

def route_query(query: str) -> str:
    """Route query to an intent without an LLM call (~5ms)."""
    query_emb = embed(query)
    scores = {
        intent: cosine_similarity(query_emb, proto_emb)
        for intent, proto_emb in prototype_embeddings.items()
    }
    return max(scores, key=scores.get)

import json
import redis
from dataclasses import dataclass, asdict
from datetime import datetime

r = redis.Redis(host="localhost", port=6379, decode_responses=True)

@dataclass
class SessionContext:
    user_id: str
    session_id: str
    messages: list[dict]
    summary: str | None
    created_at: str
    updated_at: str

    def to_json(self) -> str:
        return json.dumps(asdict(self))

    @classmethod
    def from_json(cls, data: str) -> "SessionContext":
        return cls(**json.loads(data))

class SessionStore:
    TTL_SECONDS = 3600 * 4  # Sessions expire after 4 hours of inactivity

    def get_session(self, session_id: str) -> SessionContext | None:
        key = f"session:{session_id}"
        data = r.get(key)
        if data:
            r.expire(key, self.TTL_SECONDS)  # Refresh TTL on access
            return SessionContext.from_json(data)
        return None

    def save_session(self, session: SessionContext):
        key = f"session:{session.session_id}"
        session.updated_at = datetime.utcnow().isoformat()
        r.setex(key, self.TTL_SECONDS, session.to_json())

    def create_session(self, user_id: str, session_id: str) -> SessionContext:
        session = SessionContext(
            user_id=user_id,
            session_id=session_id,
            messages=[],
            summary=None,
            created_at=datetime.utcnow().isoformat(),
            updated_at=datetime.utcnow().isoformat()
        )
        self.save_session(session)
        return session

    def add_turn(self, session_id: str, role: str, content: str):
        """Thread-safe turn append using Redis atomic operations."""
        session = self.get_session(session_id)
        if not session:
            raise ValueError(f"Session {session_id} not found")
        session.messages.append({"role": role, "content": content})
        self.save_session(session)

from openai import OpenAI

client = OpenAI()

def compress_context_block(
    content: str,
    target_tokens: int,
    preserve_facts: str = "all key facts, numbers, names, and decisions"
) -> str:
    """
    Abstractive compression: use an LLM to rewrite content
    in fewer tokens while preserving semantic content.
    """
    response = client.chat.completions.create(
        model="gpt-4o-mini",  # Use a fast, cheap model for compression
        messages=[
            {
                "role": "system",
                "content": f"""Compress the following text to approximately {target_tokens} tokens.
Preserve: {preserve_facts}.
Do NOT:
- Add information not in the original
- Remove specific numbers, names, or decisions
- Change the meaning of any statement
Output ONLY the compressed text, no commentary."""
            },
            {"role": "user", "content": content}
        ],
        max_tokens=target_tokens + 100  # Slight buffer
    )
    return response.choices[0].message.content

def priority_aware_compression(
    context_layers: dict[str, str],  # {layer_name: content}
    token_budget: int,
    priorities: dict[str, int],      # {layer_name: priority (lower=higher)}
    encoder
) -> dict[str, str]:
    """
    Compress lower-priority layers when total budget is exceeded.
    Never compresses P0 (required) layers.
    """
    total_tokens = sum(
        len(encoder.encode(content))
        for content in context_layers.values()
    )

    if total_tokens <= token_budget:
        return context_layers  # No compression needed

    compressed = dict(context_layers)
    excess = total_tokens - token_budget

    # Compress layers from lowest priority to highest
    for layer_name in sorted(priorities, key=lambda k: -priorities[k]):
        if priorities[layer_name] == 0:
            continue  # Never compress required layers

        content = compressed[layer_name]
        current_tokens = len(encoder.encode(content))
        target_tokens = max(100, current_tokens - excess)

        if target_tokens < current_tokens:
            compressed[layer_name] = compress_context_block(content, target_tokens)
            excess -= (current_tokens - target_tokens)

        if excess <= 0:
            break

    return compressed

from dataclasses import dataclass
from typing import Callable

@dataclass
class ContextVariant:
    name: str
    assemble_fn: Callable[[str], list[dict]]  # (query) -> messages

def run_context_ab_test(
    variants: list[ContextVariant],
    test_cases: list[dict],  # [{query, expected_answer, context_docs}]
    evaluate_fn: Callable
) -> dict:
    """Run multiple context assembly strategies against a golden test set."""
    results = {v.name: {"scores": [], "avg": 0.0, "cost": 0.0} for v in variants}

    for case in test_cases:
        for variant in variants:
            messages = variant.assemble_fn(case["query"])
            response = call_llm(messages)  # Your LLM wrapper
            score = evaluate_fn(
                context_docs=case.get("context_docs", ""),
                query=case["query"],
                response=response
            )
            results[variant.name]["scores"].append(score["score"])

    for name in results:
        scores = results[name]["scores"]
        results[name]["avg"] = sum(scores) / len(scores)

    return results

